kubectl patch statefulset es-cluster -n elasticsearch --type strategic -p '{
  "spec": {
    "template": {
      "spec": {
        "initContainers": [
          {
            "name": "keystore-setup",
            "image": "docker.elastic.co/elasticsearch/elasticsearch:8.11.1",
            "command": ["sh", "-c", "elasticsearch-keystore create -p '"'"''"'"' 2>/dev/null; printf \"%s\" \"$ACCESS_KEY\" | elasticsearch-keystore add --stdin s3.client.default.access_key; printf \"%s\" \"$SECRET_KEY\" | elasticsearch-keystore add --stdin s3.client.default.secret_key; cp /usr/share/elasticsearch/config/elasticsearch.keystore /keystore-vol/elasticsearch.keystore; echo keystore-setup done"],
            "env": [
              {"name": "ACCESS_KEY", "valueFrom": {"secretKeyRef": {"name": "es-secure-settings", "key": "s3.client.default.access_key"}}},
              {"name": "SECRET_KEY", "valueFrom": {"secretKeyRef": {"name": "es-secure-settings", "key": "s3.client.default.secret_key"}}}
            ],
            "volumeMounts": [
              {"name": "keystore-vol", "mountPath": "/keystore-vol"}
            ],
            "securityContext": {"runAsUser": 1000}
          }
        ],
        "containers": [
          {
            "name": "elasticsearch",
            "volumeMounts": [
              {"name": "keystore-vol", "mountPath": "/usr/share/elasticsearch/config/elasticsearch.keystore", "subPath": "elasticsearch.keystore"}
            ]
          }
        ],
        "volumes": [
          {"name": "keystore-vol", "emptyDir": {}}
        ]
      }
    }
  }
}' 2>&1

